import React from 'react'
import Polygon from "../../assets/images/Polygon.png";
import { Link } from "react-router-dom";
import Axios from '../../Config/Axios'
import { toastAlert, getSession, updateSession, getToken } from "../../Helpers/Functions";
import Redirect from "../../Utils/history";
import userAuthenicated from '../../Services/auth.service';
import ApiRequest from "../../Services/ApiRequest";
import axios from 'axios';



class GetStarted extends React.Component {

    state = {
        isAnimationLoaded: false,
        user_role_id: '',
        experience: '',
        loading: false,
        errors: {
            user_role_id: '',
            experience: ''
        },
        roles: [],
        getExperience: [],
    }

    componentDidMount = async () => {
        axios.defaults.headers.common['Authorization'] = getToken()
        let user = getSession();
        this.setState({
            user_role_id: user.__userDetail.roles.length ? user.__userDetail.roles[0].id : '',
            experience: user.__userDetail.experience.length ? user.__userDetail.experience[0].id : '',
        })

        // Get Roles
        const getRoles = await ApiRequest.getRequest('/role')
        if (getRoles && getRoles.status === 200) {
            this.setState({
                roles: getRoles.data.roles
            })
        }

        // Get Experience
        const getExperience = await ApiRequest.getRequest('/getExperience')
        if (getExperience && getExperience.status === 200) {
            console.log(getExperience);
            this.setState({
                getExperience: getExperience.data.experience
            })
        }

    }
    onChangeState = (event) => {
        const { name, value } = event.target;
        this.setState({ [name]: value })
        console.log('name', this.state.user_role_id);

    }
    getUserRole() {
        Axios.get('role').then(response => {
            // console.log(response);
        })
    }
    getStartedForm = () => {
        console.log(this.state);
        const { user_role_id, experience } = this.state;
        let { roleError, experienceError } = '';
        if (!user_role_id) {
            roleError = "Please select one of these options.";
        }

        if (!experience) {
            experienceError = "Please select one of these options.";
        }

        this.setState({
            errors: {
                user_role_id: roleError,
                experience: experienceError
            }
        })
        if (roleError || experienceError) {
            return true;
        }
        this.setState({ loading: true });
        Axios.post(`/role/save`, { user_role_id, experience }).then(response => {
            if (response.status == 200) {
                const data = {
                    __userDetail: response.data.user[0]
                }
                updateSession(data);
                console.log('update ' + JSON.stringify(data))
                userAuthenicated.userRedirectHandler(response);

                // window.location.href = '/';
            } else {
                toastAlert('error', 'Authentication Failed!');
            }
        }).catch(error => {
            // console.log(error.response, 'error data')

            toastAlert('error', 'Authentication Failed!')
            //
            // return error.response
        }).finally(() => {
            this.setState({ loading: false });
        });

    }
    getRoles() {
        if (this.state.roles.length !== 0) {
            return (
                <select name="user_role_id" onChange={this.onChangeState}
                    value={this.state.user_role_id}
                >
                    <option disable>Select Career here</option>
                    {this.state.roles.map(el => {
                        return (
                            <option value={el.id}>{el.name}</option>
                        )
                    })}
                </select>
            );
        }
    }
    getExperience() {
        if (this.state.roles.length !== 0) {
            return (
                <select name="experience" onChange={this.onChangeState}
                    value={this.state.experience}
                >
                    <option>Select Years</option>
                    {this.state.getExperience.map(el => {
                        return (
                            <option value={el.id}>{el.title}</option>
                        )
                    })}
                </select>
            );
        }
    }

    render() {
        return (
            <>
                <div className="container-fluid getLanding-wrapper form-wrap vh-100">
                    <div className="row mar-width-0 width-wrap-2">
                        <form>
                            <div className="col-md-12 started-heading">
                                <h2>Get Started!</h2>
                            </div>
                            <div className="col-md-12 Landing-heading ">
                                <h6>
                                    I want to Obtain Role as a:
                                </h6>
                                <div className="form-group" >
                                    <div className="select-style-2 w-100">
                                        {/* <select name="user_role_id" onChange={this.onChangeState} value={this.state.user_role_id}>
                                        <option disable>Select Career here</option>
                                        <option value="2">Become a Mentor</option>
                                        <option value="3">Become a Mentee</option>

                                    </select> */}
                                        {this.getRoles()}
                                        <img src={Polygon} className="Polygon-icon" alt="" />
                                        <span className="error">{this.state.errors.user_role_id}</span>
                                    </div>
                                </div>
                            </div>
                            <div className="col-md-12 Landing-heading ">
                                <h6 className="h6-flex">
                                    And I have
                                    <div className="select-style-2 experience">
                                        {/* <select name="experience" onChange={this.onChangeState} value={this.state.experience}>
                                            <option value="1">1</option>
                                            <option value="2">2</option>
                                            <option value="3">3</option>
                                            <option value="4">4</option>
                                            <option value="5">5</option>
                                        </select> */}
                                        {this.getExperience()}
                                        <img src={Polygon} className="Polygon-icon" alt="" />
                                    </div>
                                    Years of Industry Experience
                                </h6>

                                <span className="error">{this.state.errors.experience}</span>
                            </div>
                            <div className="col-md-12 bottom-wrap pb-0 text-center">
                                {/* <Link to="/login" className="btn btn-primary btnSignUp">Lets Go</Link> */}

                                <button type="button" disabled={this.state.loading} onClick={this.getStartedForm} className="btn btn-primary btnSignUp">Lets Go</button>
                            </div>
                        </form>
                        <div className="col-md-12 bottom-wrap pb-0 text-center mt-2">
                            <span> <Link to="/" className="text-decoration-none login-link">Go Back</Link></span>
                        </div>
                    </div>
                </div>
            </>
        )
    }
}

export default GetStarted
